module RefModule(
   clk,
   reset,
   count_out
);input            clk;
    input            reset;
    output  [3:0]    count_out;

    reg  [3:0]        obf_count_out_reg;

    always @(posedge clk or negedge reset) begin
        if (~reset) begin
            obf_count_out_reg <= 4'b0000;
        end
        else begin
            obf_count_out_reg <= obf_count_out_reg + 1;
        end
    end

    assign count_out = obf_count_out_reg;

endmodule
